#include <stdio.h>
int main() {
    int arr[100000], n;
    printf("Enter the number of elements: ");
    scanf("%d", &n);
    printf("Enter the elements: ");
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    for (int window = 1; window <= n; window++) {
        int maxMin = -1;
        for (int i = 0; i <= n - window; i++) {
            int min = arr[i];
            for (int j = 1; j < window; j++) {
                if (arr[i + j] < min) {
                    min = arr[i + j];
                }
            }
            if (min > maxMin) {
                maxMin = min;
            }
        }
        printf("%d ", maxMin);
    }
    return 0;
}

