def max_of_mins(arr):
    n = len(arr)
    for window in range(1, n + 1):
        max_min = -1
        for i in range(n - window + 1):
            min_val = arr[i]
            for j in range(1, window):
                if arr[i + j] < min_val:
                    min_val = arr[i + j]
            if min_val > max_min:
                max_min = min_val
        print(max_min, end=' ')

