const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let arr;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else if (i === 1) {
        arr = line.split(' ').map(num => parseInt(num));
        for (let window = 1; window <= n; window++) {
            let maxMin = -1;
            for (let j = 0; j <= n - window; j++) {
                let min = arr[j];
                for (let k = 1; k < window; k++) {
                    if (arr[j + k] < min) {
                        min = arr[j + k];
                    }
                }
                if (min > maxMin) {
                    maxMin = min;
                }
            }
            process.stdout.write(maxMin + ' ');
        }
    }
    i++;
});

